<?phpnamespace App\Service;use PDO;class DynamicTableReader{ private PDO $db; public function __construct(PDO $db) { $this->db=$db;} public function getSlotById(int $id, string $type): array { $tableName='booking_slot_' . $type; $stmt=$this->db->prepare( "SELECT s.*, v.code FROM{$tableName} AS s JOIN slot_variants AS v ON s.variant_id=v.id WHERE s.id=:id AND s.active=1" ); $stmt->execute(['id'=>$id]); return $stmt->fetch(PDO::FETCH_ASSOC) ?: [];} public function countActiveSlots(string $type): int { $tableName='booking_slot_' . $type; $stmt=$this->db->query("SELECT COUNT(*) FROM{$tableName} WHERE active=1"); return (int) $stmt->fetchColumn();}}